// CONFIGURATION: Nom du dossier/fichier cible
const NOM_CIBLE = 'template rapport';

const items = $input.all();

if (!items || items.length === 0) {
  return [{
    json: {
      success: false,
      timestamp: new Date().toISOString(),
      message: "Aucun élément trouvé dans Google Drive",
      contenu: []
    }
  }];
}

// Chercher tous les éléments qui correspondent au nom cible
const elementsTrouves = [];
const cibleLower = NOM_CIBLE.toLowerCase().trim();

for (const item of items) {
  const data = item.json;
  if (!data || !data.id) continue;

  const nomLower = (data.name || '').toLowerCase().trim();

  // Correspondance exacte ou avec variantes
  if (nomLower === cibleLower || 
      nomLower === cibleLower.replace(/ /g, '_') ||
      nomLower === cibleLower.replace(/ /g, '')) {
    elementsTrouves.push({
      fichier_id: data.id,
      fichier_nom: data.name,
      fichier_mimeType: data.mimeType || 'unknown',
      dossier_parent_id: NOM_CIBLE,
      dossier_parent_nom: NOM_CIBLE
    });
  }
}

if (elementsTrouves.length === 0) {
  // Chercher des correspondances partielles
  const correspondancesPartielles = items
    .filter(i => i.json && i.json.name && i.json.name.toLowerCase().includes(cibleLower.split(' ')[0]))
    .map(i => i.json.name)
    .slice(0, 20);

  return [{
    json: {
      success: false,
      timestamp: new Date().toISOString(),
      message: `Aucun élément nommé '${NOM_CIBLE}' trouvé`,
      recherche: NOM_CIBLE,
      correspondancesPartielles: correspondancesPartielles,
      contenu: []
    }
  }];
}

return [{
  json: {
    success: true,
    timestamp: new Date().toISOString(),
    recherche: NOM_CIBLE,
    statistiques: {
      totalTrouves: elementsTrouves.length
    },
    contenu: elementsTrouves
  }
}];
